import{_ as i,o as t,c as s,a6 as e}from"./chunks/framework.wLlb4ebq.js";const b=JSON.parse('{"title":"通用网页与 Obsidian","description":"","frontmatter":{},"headers":[],"relativePath":"features/web-obsidian.md","filePath":"features/web-obsidian.md"}'),n={name:"features/web-obsidian.md"};function d(l,a,r,h,o,p){return t(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="通用网页与-obsidian" tabindex="-1">通用网页与 Obsidian <a class="header-anchor" href="#通用网页与-obsidian" aria-label="Permalink to “通用网页与 Obsidian”">​</a></h1><p>LD-Notion 不只运行在 Linux.do、GitHub 和 Notion，也可以在通用网页上提供剪藏入口，并支持导出到 Obsidian。</p><h2 id="通用网页剪藏" tabindex="-1">通用网页剪藏 <a class="header-anchor" href="#通用网页剪藏" aria-label="Permalink to “通用网页剪藏”">​</a></h2><p>通用网页入口会抽取：</p><ul><li>页面标题。</li><li>来源 URL。</li><li>站点信息。</li><li>摘要候选。</li><li>主要正文线索。</li><li>图片与链接信息。</li></ul><p>为了避免干扰常用搜索、邮箱、localhost 等页面，脚本头部排除了一部分站点。</p><h2 id="字符集与内容清洗" tabindex="-1">字符集与内容清洗 <a class="header-anchor" href="#字符集与内容清洗" aria-label="Permalink to “字符集与内容清洗”">​</a></h2><p>网页内容可能不是 UTF-8。LD-Notion 会按以下顺序处理：</p><div class="language-mermaid"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Response[网页响应] --&gt; Header{响应头 charset?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Header --&gt;|有| Decode1[按响应头解码]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Header --&gt;|无| Meta{HTML meta charset?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Meta --&gt;|有| Decode2[按 meta 解码]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Meta --&gt;|无| Fallback[按 utf-8 / gb18030 / big5 / shift_jis 回退]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Decode1 --&gt; Clean[清理 script/style/noscript/template]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Decode2 --&gt; Clean</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Fallback --&gt; Clean</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Clean --&gt; Extract[抽取标题 / 摘要 / 正文线索]</span></span></code></pre></div><h2 id="obsidian-导出" tabindex="-1">Obsidian 导出 <a class="header-anchor" href="#obsidian-导出" aria-label="Permalink to “Obsidian 导出”">​</a></h2><p>Obsidian 导出面向本地知识库，通常依赖 Obsidian Local REST API。</p><p>常见配置：</p><table tabindex="0"><thead><tr><th>配置</th><th>说明</th></tr></thead><tbody><tr><td>Obsidian API URL</td><td>默认类似 <code>https://127.0.0.1:27124</code></td></tr><tr><td>API Key</td><td>Local REST API 的授权 Key</td></tr><tr><td>输出目录</td><td>默认可使用 <code>Linux.do</code></td></tr><tr><td>图片目录</td><td>默认可使用 <code>Linux.do/attachments</code></td></tr><tr><td>图片模式</td><td>文件、base64 或跳过</td></tr></tbody></table><h2 id="notion-与-obsidian-的选择" tabindex="-1">Notion 与 Obsidian 的选择 <a class="header-anchor" href="#notion-与-obsidian-的选择" aria-label="Permalink to “Notion 与 Obsidian 的选择”">​</a></h2><table tabindex="0"><thead><tr><th>目标</th><th>适合场景</th></tr></thead><tbody><tr><td>Notion</td><td>结构化数据库、协作、在线检索、AI 工作区管理</td></tr><tr><td>Obsidian</td><td>本地 Markdown、双链笔记、长期离线沉淀</td></tr></tbody></table><p>两者可以并行使用：Notion 承担跨源数据库和协作层，Obsidian 承担本地归档层。</p>`,16)])])}const k=i(n,[["render",d]]);export{b as __pageData,k as default};
